import{_ as o,c as n,o as r,ai as t}from"./chunks/framework.CM7c3k__.js";const g=JSON.parse('{"title":"New General Members join NeoNephos","description":"","frontmatter":{"title":"New General Members join NeoNephos","date":"2025-08-25","banner":"assets/blog/20250825_neonephos_new_general_members_banner.jpg","authors":["neonephos-team"],"tags":["2025","news"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"BlogEntryThemeComponent"},"headers":[],"relativePath":"blog/20250825_neonephos_new_general_members_announcement.md","filePath":"blog/20250825_neonephos_new_general_members_announcement.md"}'),a={name:"blog/20250825_neonephos_new_general_members_announcement.md"};function s(i,e,l,p,h,m){return r(),n("div",null,e[0]||(e[0]=[t('<h1 id="new-general-members-join-neoneonephos" tabindex="-1">New General Members join NeoNeoNephos <a class="header-anchor" href="#new-general-members-join-neoneonephos" aria-label="Permalink to &quot;New General Members join NeoNeoNephos&quot;">​</a></h1><p><strong>Open Source Summit, Amsterdam, NL – August 25, 2025</strong> – The NeoNephos Foundation, which supports projects that align with the strategic objectives of the EU’s IPCEI-CIS, is excited to announce the addition of four new General Members.</p><p><strong>New General Members</strong></p><ul><li><a href="https://www.reply.com/liquid-reply/en" target="_blank" rel="noreferrer">Liquid Reply</a></li><li><a href="https://www.apefactory.com/en" target="_blank" rel="noreferrer">Ape Factory</a></li><li><a href="https://www.nearbycomputing.com/" target="_blank" rel="noreferrer">Nearby Computing</a></li><li><a href="https://www.kubermatic.com/" target="_blank" rel="noreferrer">Kubermatic</a></li></ul><p>The addition of these partners highlights NeoNephos’ commitment to inviting the industry at large in shaping the future of sovereign cloud-native technology collaboratively, all under the umbrella of the Linux Foundation Europe.</p><p><strong>About NeoNephos</strong><br> NeoNephos, part of Linux Foundation Europe, provides a sustainable, shared development model for projects of the cloud-edge continuum and offers collaborative potential for higher adoption. By being open to hosting projects from other industry players and the community at large, the foundation provides a nurturing environment for any project sharing the goal of a sovereign, open, enterprise-hardened, multi provider cloud-to-edge continuum.<br> Contributions to NeoNephos can be conducted in a variety of ways: by <a href="https://github.com/neonephos" target="_blank" rel="noreferrer">participating in projects</a>, <a href="https://neonephos.org/projects" target="_blank" rel="noreferrer">donating entire projects</a> or <a href="https://neonephos.org/join/" target="_blank" rel="noreferrer">becoming a member</a> (if you are an organization).</p><p>Follow along on the journey by <a href="https://neonephos.org/" target="_blank" rel="noreferrer">subscribing to the newsletter</a>.</p>',7)]))}const c=o(a,[["render",s]]);export{g as __pageData,c as default};
